def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            threshold = j * 0.1
            if ratio < threshold:
                score += (11 - j) * 0.3
            else:
                score -= j * 0.05
            if j % 2 == 0:
                score += 0.1 * (capacity % (j+1))
            else:
                score -= 0.05 * (item % (j+1))
        if capacity % 3 == 0:
            score *= 1.2
            if item % 2 == 0:
                score += 0.5
            else:
                score -= 0.3
        elif capacity % 3 == 1:
            score *= 0.8
            if item > capacity / 2:
                score += 0.4
            else:
                score -= 0.2
        else:
            score *= 1.0
            for k in range(1, 4):
                if (item * k) % capacity < capacity * 0.1:
                    score += 0.2 * k
                else:
                    score -= 0.1 * k
        if score < 0:
            score = abs(score) * 0.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 15
    return priorities
